#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y, K;
        scanf("%lld %lld %lld", &X, &Y, &K);
        long long g = gcd_ll(X, Y);
        long long ans;
        if (K == 1) {
            long long mn = X < Y ? X : Y;
            ans = g + mn;
        } else {
            ans = 2 * g;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

