#!/usr/bin/env python3
import sys, math
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); K = int(next(it))
        g = math.gcd(X, Y)
        if K == 1:
            ans = g + min(X, Y)
        else:
            ans = 2 * g
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

